function [res] = ANN_model(params)
    % input --> [M m0 n0 phi alpha]
    % output --> [input  f''(0)(water)  f''(0)(EO)  g'(0)(water)  g'(0)(EO)  -theta'(0)(water)  -theta'(0)(EO)]
    
    M = params(:,1); m0 = params(:,2); n0 = params(:,3); phi = params(:,4); alpha = params(:,5);
    
    n = length(params);
    res = [];

    for i = 1:n
        crit_alpha = critAlphaModel([ M(i) m0(i) n0(i) phi(i) ]);
        if alpha(i) < crit_alpha   % 0.005 is the assumed margin of error
            res = [res; M(i) m0(i) n0(i) phi(i) alpha(i) NaN NaN NaN NaN NaN NaN];
        else
            skinFriction = skinFrictionModel([ M(i) m0(i) n0(i) phi(i) alpha(i) ]);
            nusseltNo = nusseltNoModel([ M(i) m0(i) n0(i) phi(i) alpha(i) ]);
            res = [res;  M(i) m0(i) n0(i) phi(i) alpha(i) skinFriction nusseltNo];
        end
    end
end


